#!/bin/bash

# Backup MySQL Databases

# Connect to MySQL and create a dump of all databases in the backup directory
mysqldump -h localhost -u backup_user -p'BackupPass123' --all-databases > /home/backup/db_backup.sql

# Create a timestamp for the backup file name
TIMESTAMP=$(date +%Y-%m-%d_%H:%M)

# Rename the dump file to include the timestamp and add .sql extension
mv db_backup.sql db_backup_$TIMESTAMP.sql

# Compress the dump file using gzip compression
gzip -9 db_backup_$TIMESTAMP.sql

# Move the compressed backup file into the backup directory
mv db_backup_$TIMESTAMP.sql.gz /home/backup

# Print a message indicating that the backup was successful
echo "Database Backup Successful"

# End of Code